module top_module(Invalid_Clock,D,Qa,Qb,Qc);input Invalid_Clock;
    input D;
    output reg Qa,Qb,Qc;

    always @ (Invalid_Clock or D)
    if(Invalid_Clock)
    begin
        Qa <= D;
    end

    always @ (posedge Invalid_Clock)
    begin
        Qb <= D;
    end

    always @ (negedge Invalid_Clock)
    begin
        Qc <= D;
    end
endmodule
